diff --git a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
index 00efd3c0eb72..150774c7785a 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -5538,7 +5538,215 @@ static void createUnreachableSwitchDefault(SwitchInst *Switch,
   }
 }

-/// Turn a switch into an integer range comparison and branch.
+/// Switch on ucmp/scmp produces values -1, 0, 1 representing LT, EQ, GT.
+/// If the switch has only two destinations, we can turn it into a direct icmp.
+static bool tryOptimizeSwitchOnCmpIntrinsic(SwitchInst *SI, IRBuilder<> &Builder,
+                                            DomTreeUpdater *DTU) {
+  // Only optimize switches with exactly 2 unique destinations (including default).
+  SmallVector<BasicBlock *, 4> UniqueDests;
+  for (auto Case : SI->cases()) {
+    BasicBlock *Dest = Case.getCaseSuccessor();
+    if (!is_contained(UniqueDests, Dest))
+      UniqueDests.push_back(Dest);
+  }
+  
+  BasicBlock *DefaultDest = SI->getDefaultDest();
+  bool HasDefaultSucc = is_contained(UniqueDests, DefaultDest);
+  
+  // Need at most 2 destinations total (including default).
+  if (UniqueDests.size() > 2)
+    return false;
+  if (UniqueDests.empty())
+    return false;
+
+  // Check if condition is a ucmp/scmp intrinsic.
+  auto *CondII = dyn_cast<IntrinsicInst>(SI->getCondition());
+  if (!CondII)
+    return false;
+  
+  Intrinsic::ID IID = CondII->getIntrinsicID();
+  bool IsSigned;
+  if (IID == Intrinsic::scmp)
+    IsSigned = true;
+  else if (IID == Intrinsic::ucmp)
+    IsSigned = false;
+  else
+    return false;
+
+  // Check that the cmp result is only used by this switch.
+  if (!CondII->hasOneUse())
+    return false;
+
+  // Collect which cases go where.
+  // ucmp/scmp returns: -1 (LT), 0 (EQ), 1 (GT).
+  // Index 0 = -1 (LT), Index 1 = 0 (EQ), Index 2 = 1 (GT)
+  // Value: 0 = default, 1 = other
+  int CaseToDest[3] = {-1, -1, -1}; 
+  BasicBlock *DestA = nullptr, *DestB = nullptr;
+  
+  for (auto Case : SI->cases()) {
+    const APInt &Val = Case.getCaseValue()->getValue();
+    // Check that the value is in range [-1, 1].
+    if (!Val.isSignedIntN(2))
+      return false;
+    int SV = Val.getSExtValue();
+    if (SV < -1 || SV > 1)
+      return false;
+    // Convert -1, 0, 1 to index 0, 1, 2.
+    int Idx = SV + 1;
+    BasicBlock *Succ = Case.getCaseSuccessor();
+    if (!DestA)
+      DestA = Succ;
+    else if (DestA != Succ && !DestB)
+      DestB = Succ;
+    CaseToDest[Idx] = (Succ == DestA) ? 0 : 1;
+  }
+
+  // If all cases go to the same destination but the default is different,
+  // set DestB to the default destination.
+  if (!DestB && DefaultDest != DestA)
+    DestB = DefaultDest;
+
+  // Set CaseToDest for any missing values to the default destination.
+  for (int i = 0; i < 3; ++i) {
+    if (CaseToDest[i] == -1)
+      CaseToDest[i] = (DefaultDest == DestA) ? 0 : 1;
+  }
+
+  // Default is always DestA in this scheme.
+  int DefaultIdx = (DefaultDest == DestA) ? 0 : 1;
+
+  // Determine which icmp predicate to use based on the case distribution.
+  CmpInst::Predicate Pred;
+  bool SwapDest = false;
+  
+  if (CaseToDest[0] != -1 && CaseToDest[0] == CaseToDest[1]) {
+    // -1 and 0 together: LE vs GT -> use GT with swapped destinations
+    Pred = IsSigned ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_UGT;
+    SwapDest = true;
+  } else if (CaseToDest[1] != -1 && CaseToDest[1] == CaseToDest[2]) {
+    // 0 and 1 together: GE vs LT -> use LT
+    Pred = IsSigned ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_ULT;
+  } else if (CaseToDest[0] != -1 && CaseToDest[0] == CaseToDest[2]) {
+    // -1 and 1 together: NE vs EQ -> use EQ with swapped destinations
+    Pred = ICmpInst::ICMP_EQ;
+    SwapDest = true;
+  } else if (CaseToDest[0] != -1 && CaseToDest[1] == -1 && CaseToDest[2] == -1) {
+    // Only -1: LT vs (everything else) -> use LT
+    Pred = IsSigned ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_ULT;
+  } else if (CaseToDest[1] != -1 && CaseToDest[0] == -1 && CaseToDest[2] == -1) {
+    // Only 0: EQ vs (everything else) -> use EQ
+    Pred = ICmpInst::ICMP_EQ;
+  } else if (CaseToDest[2] != -1 && CaseToDest[0] == -1 && CaseToDest[1] == -1) {
+    // Only 1: GT vs (everything else) -> use GT
+    Pred = IsSigned ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_UGT;
+  } else {
+    return false;
+  }
+
+  // Determine TrueDest and FalseDest.
+  BasicBlock *TrueDest, *FalseDest;
+  int PredTrueDest, PredFalseDest;
+  
+  if (SwapDest) {
+    // Comparison being true means we go to the "other" destination
+    // (the one not in the shared group).
+    if (CaseToDest[0] != -1 && CaseToDest[1] != -1 && CaseToDest[0] == CaseToDest[1]) {
+      // -1 and 0 are together, so 1 (GT) is the "other" case.
+      PredTrueDest = CaseToDest[2];
+    } else if (CaseToDest[0] != -1 && CaseToDest[2] != -1 && CaseToDest[0] == CaseToDest[2]) {
+      // -1 and 1 are together, so 0 (EQ) is the "other" case.
+      PredTrueDest = CaseToDest[1];
+    } else {
+      // Default: use the destination of the first available case.
+      // This handles single-case switches.
+      if (CaseToDest[0] != -1)
+        PredTrueDest = CaseToDest[0];
+      else if (CaseToDest[1] != -1)
+        PredTrueDest = CaseToDest[1];
+      else
+        PredTrueDest = CaseToDest[2];
+    }
+  } else {
+    // Comparison being true means we go to the default's complement.
+    if (DefaultIdx == 0) {
+      // Default is DestA, so true goes to DestB (if it exists).
+      PredTrueDest = (DestB && CaseToDest[1] == 1) ? 1 : 0;
+    } else {
+      PredTrueDest = 0;
+    }
+  }
+  PredFalseDest = 1 - PredTrueDest;
+  
+  TrueDest = (PredTrueDest == 0) ? DestA : DestB;
+  FalseDest = (PredFalseDest == 0) ? DestA : DestB;
+
+  // Create the icmp.
+  Builder.SetInsertPoint(SI);
+  Value *LHS = CondII->getOperand(0);
+  Value *RHS = CondII->getOperand(1);
+  Value *Cmp = Builder.CreateICmp(Pred, LHS, RHS, "switch.cmp");
+  BranchInst *NewBI = Builder.CreateCondBr(Cmp, TrueDest, FalseDest);
+
+  // Transfer branch weights if present.
+  if (hasBranchWeightMD(*SI)) {
+    SmallVector<uint64_t, 8> Weights;
+    getBranchWeights(SI, Weights);
+    if (Weights.size() == 1 + SI->getNumCases()) {
+      uint64_t TrueWeight = 0, FalseWeight = 0;
+      for (size_t I = 0, E = Weights.size(); I != E; ++I) {
+        if (SI->getSuccessor(I) == TrueDest)
+          TrueWeight += Weights[I];
+        else
+          FalseWeight += Weights[I];
+      }
+      while (TrueWeight > UINT32_MAX || FalseWeight > UINT32_MAX) {
+        TrueWeight /= 2;
+        FalseWeight /= 2;
+      }
+      setBranchWeights(NewBI, TrueWeight, FalseWeight, /*IsExpected=*/false);
+    }
+  }
+
+  // Remove dead edges from PHI nodes.
+  for (auto BBI = TrueDest->begin(); isa<PHINode>(BBI); ++BBI) {
+    int NumRemovals = 0;
+    for (auto Case : SI->cases()) {
+      if (Case.getCaseSuccessor() == TrueDest)
+        ++NumRemovals;
+    }
+    if (TrueDest == DefaultDest)
+      ++NumRemovals;
+    for (int I = 0; I < NumRemovals - 1; ++I)
+      cast<PHINode>(BBI)->removeIncomingValue(SI->getParent());
+  }
+  for (auto BBI = FalseDest->begin(); isa<PHINode>(BBI); ++BBI) {
+    int NumRemovals = 0;
+    for (auto Case : SI->cases()) {
+      if (Case.getCaseSuccessor() == FalseDest)
+        ++NumRemovals;
+    }
+    if (FalseDest == DefaultDest)
+      ++NumRemovals;
+    for (int I = 0; I < NumRemovals - 1; ++I)
+      cast<PHINode>(BBI)->removeIncomingValue(SI->getParent());
+  }
+
+  // Handle unreachable default.
+  if (isa<UnreachableInst>(DefaultDest->getFirstNonPHIOrDbg()))
+    createUnreachableSwitchDefault(SI, DTU);
+
+  // Drop the switch and the cmp intrinsic.
+  BasicBlock *BB = SI->getParent();
+  SI->eraseFromParent();
+  CondII->eraseFromParent();
+
+  if (DTU && isa<UnreachableInst>(DefaultDest->getFirstNonPHIOrDbg()))
+    DTU->applyUpdates({{DominatorTree::Delete, BB, DefaultDest}});
+
+  return true;
+}
+
 /// Switches with more than 2 destinations are ignored.
 /// Switches with 1 destination are also ignored.
 bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,
@@ -7153,6 +7361,11 @@ bool SimplifyCFGOpt::simplifySwitch(SwitchInst *SI, IRBuilder<> &Builder) {
         return requestResimplify();
   }

+  // Try to optimize switches on ucmp/scmp intrinsics first.
+  // This is always safe because ucmp/scmp can only return -1, 0, or 1.
+  if (tryOptimizeSwitchOnCmpIntrinsic(SI, Builder, DTU))
+    return requestResimplify();
+
   // Try to transform the switch into an icmp and a branch.
   // The conversion from switch to comparison may lose information on
   // impossible switch values, so disable it early in the pipeline.
